/// <summary>
/// Reads customer data through the SysDa fluent data access API instead of an X++ select statement.
/// </summary>
public class ConDemoSysDaReader
{
}

Method.Source:
/// <summary>
/// Collects the account numbers of the customers that are not blocked.
/// </summary>
/// <returns>
/// A container that holds one account number per non blocked customer.
/// </returns>
/// <remarks>
/// The query is built with the SysDa fluent API and executed through a SysDaSearchObject.
/// </remarks>
public static container blockedCustomerAccounts()
{
    CustTable               custTable;
    container               accounts;
    SysDaQueryObject        queryObject;
    SysDaSearchObject       searchObject;
    SysDaSearchStatement    searchStatement;

    queryObject = new SysDaQueryObject(custTable);
    queryObject.projection().add(fieldStr(CustTable, AccountNum));
    queryObject.whereClause(new SysDaEqualsExpression(
    new SysDaFieldExpression(custTable, fieldStr(CustTable, Blocked)),
    new SysDaValueExpression(enum2int(CustVendorBlocked::No))));

    searchObject    = new SysDaSearchObject(queryObject);
    searchStatement = new SysDaSearchStatement();

    while (searchStatement.next(searchObject))
    {
        accounts += custTable.AccountNum;
    }

    return accounts;
}
